// Write a function called isPalindrome that takes a string s as input and returns true if it's a palindrome, and false otherwise.
function isPalindrome(s) {
    // Remove non-alphanumeric characters and convert to lowercase
    let cleanS = s.replace(/[^a-zA-Z0-9]/g, ' ').toLowerCase();
    // Check if the cleaned string is equal to its reverse
    return cleanS === cleanS.split('').reverse().join('');
}

