// Your solution here
function isPalindrome(s) {
    let cleanS = s.replace(/[^a-zA-Z0-9]/g, '').toLowerCase();
    let left = 0;
    let right = cleanS.length - 1;
    while (left < right) {
        if (cleanS[left] !== cleanS[right]) {
            return false;
        }
        left++;
        right--;
    }
    return true;
}
